import React, { useState } from 'react';

function WordCloud({ words }) {
  const [selectedWord, setSelectedWord] = useState(null);

  // We define a container size
  const containerWidth = 600;
  const containerHeight = 400;

  // Generate random positions for each word so they are NOT in a row
  const placedWords = Object.entries(words).map(([word, count]) => ({
    word,
    fontSize: Math.min(count * 5 + 15, 60),
    left: Math.random() * (containerWidth - 100),
    top: Math.random() * (containerHeight - 50),
    rotation: Math.random() * 90 - 45, // Random tilt in both directions
    color: `hsl(${Math.random() * 360}, 70%, 40%)`
  }));

  if (selectedWord) {
    return (
      <div style={{ padding: '40px', textAlign: 'center' }}>
        <h2>Drill Down: {selectedWord}</h2>
        <button onClick={() => setSelectedWord(null)}>Back to Cloud</button>
      </div>
    );
  }

  return (
    <div style={{ 
      position: 'relative', 
      width: `${containerWidth}px`, 
      height: `${containerHeight}px`, 
      margin: '0 auto',
      backgroundColor: '#fdfdfd'
    }}>
      {placedWords.map((item) => (
        <span
          key={item.word}
          onClick={() => setSelectedWord(item.word)}
          style={{
            position: 'absolute',
            left: `${item.left}px`,
            top: `${item.top}px`,
            fontSize: `${item.fontSize}px`,
            color: item.color,
            transform: `rotate(${item.rotation}deg)`,
            cursor: 'pointer',
            fontWeight: 'bold',
            whiteSpace: 'nowrap'
          }}
        >
          {item.word}
        </span>
      ))}
    </div>
  );
}

export default WordCloud;
